/**
 * Fast lookup by specialty id (slug).
 */
export const YOUNGER_SPECIALTY_BY_ID = new Map<string, YoungSpecialty>(
  YOUNGER_SPECIALTIES.map((s) => [s.id, s]),
);

/**
 * Specialties grouped by eixoId.
 */
export const YOUNGER_SPECIALTIES_BY_EIXO = YOUNGER_SPECIALTIES.reduce<
  Record<string, YoungSpecialty[]>
>((acc, s) => {
  (acc[s.eixoId] ??= []).push(s);
  return acc;
}, {});
